SELECT * FROM bi_knowledge


        AND title LIKE CONCAT('%', #{title}, '%')


        AND source_type = #{sourceType}


        AND business_domain = #{businessDomain}


        AND status = #{status}


ORDER BY create_time DESC

SELECT *, (content_vector <=> CAST(#{vectorStr} AS vector)) AS similarity FROM bi_knowledge WHERE status = 1
AND business_domain = #{domain}
ORDER BY content_vector <=> CAST(#{vectorStr} AS vector) LIMIT #{topK}
